- **CLI Commands**:
  - `ng generate store <name>` to create a new NgRx store.
  - `ng generate effect <name>` to create a new NgRx effect.

- **Latest Versions**:
  - Ensure you are using the latest version of Angular and NgRx for optimal performance and features. Check [Angular](https://angular.io/) and [NgRx](https://ngrx.io/) official websites for updates.

- **Key Config Options**:
  - In `app.module.ts`, configure the NgRx store with reducers, effects, and meta-reducers.
    ```typescript
    import { StoreModule } from '@ngrx/store';
    import { EffectsModule } from '@ngrx/effects';
    import { reducer } from './path-to-reducer';
    import { MyEffect } from './path-to-effect';

    @NgModule({
      imports: [
        StoreModule.forRoot({ myFeatureKey: reducer }),
        EffectsModule.forRoot([MyEffect]),
      ],
    })
    export class AppModule {}
    ```
  - Use `metaReducers` for global state transformations.
    ```typescript
    import { StoreDevtoolsModule } from '@ngrx/store-devtools';
    import { environment } from '../environments/environment';

    const metaReducers: MetaReducer<any>[] = !environment.production ? [storeFreeze] : [];

    @NgModule({
      imports: [
        StoreModule.forRoot(reducers, { metaReducers }),
        EffectsModule.forRoot(effects),
        StoreDevtoolsModule.instrument({ logOnly: environment.production }),
      ],
    })
    export class AppModule {}
    ```
